import{_ as a,o as e,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F03: 合約負債與營收能見度","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6442_光聖/20260504/F03_合約負債與營收能見度.md","filePath":"審計報告庫/財務審計/6442_光聖/20260504/F03_合約負債與營收能見度.md"}'),i={name:"審計報告庫/財務審計/6442_光聖/20260504/F03_合約負債與營收能見度.md"};function o(n,t,s,h,d,_){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="f03-合約負債與營收能見度" tabindex="-1">F03: 合約負債與營收能見度 <a class="header-anchor" href="#f03-合約負債與營收能見度" aria-label="Permalink to &quot;F03: 合約負債與營收能見度&quot;">​</a></h1><blockquote><p>標的公司：6442 光聖 | 基準日期：20260504</p></blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>合約負債與未來收入的變動關係為何？訂單轉化為實質營收的速度是否出現停滯？透過合約負債（預收款）測算營收能見度。</p><hr><h2 id="🎯-專家直斷-40-80-字" tabindex="-1">🎯 專家直斷（40-80 字） <a class="header-anchor" href="#🎯-專家直斷-40-80-字" aria-label="Permalink to &quot;🎯 專家直斷（40-80 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CL839萬 vs 營收107億非有效指標。能見度繫 63% 訂單。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：25年報</li></ul><hr><h2 id="📊-診斷評級-80-150-字" tabindex="-1">📊 診斷評級（80-150 字） <a class="header-anchor" href="#📊-診斷評級-80-150-字" aria-label="Permalink to &quot;📊 診斷評級（80-150 字）&quot;">​</a></h2><p>合約負債 10.6M→7.5M→8.4M，佔營收比 0.6%→0.3%，遠低於 5% 門檻。客戶無預付款慣例，2025 Q4 營收 28.6 億對比合約負債 0.084 億，轉化倍數 341 倍，出貨節奏極快。</p><p><strong>評級：B（持平）</strong> — 合約負債低屬行業特性，非營運弱點，但指標不具預測價值。</p><hr><h2 id="🔍-答詢詳解-200-450-字" tabindex="-1">🔍 答詢詳解（200-450 字） <a class="header-anchor" href="#🔍-答詢詳解-200-450-字" aria-label="Permalink to &quot;🔍 答詢詳解（200-450 字）&quot;">​</a></h2><h3 id="_1-合約負債現狀-現狀與特徵" tabindex="-1">1. 合約負債現狀（現狀與特徵） <a class="header-anchor" href="#_1-合約負債現狀-現狀與特徵" aria-label="Permalink to &quot;1. 合約負債現狀（現狀與特徵）&quot;">​</a></h3><p>合約負債佔營收比持續下滑至 0.29%，主因客戶採購以即時 PO 為主，長期供貨協議存在於表外。CPO 仍處驗證階段，量產前不產生大額合約負債。</p><h3 id="_2-營收能見度的真實領先指標" tabindex="-1">2. 營收能見度的真實領先指標 <a class="header-anchor" href="#_2-營收能見度的真實領先指標" aria-label="Permalink to &quot;2. 營收能見度的真實領先指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">領先指標</th><th style="text-align:right;">趨勢</th></tr></thead><tbody><tr><td style="text-align:left;">單一客戶佔比</td><td style="text-align:right;">62%→63%↑，對應 AI CAPEX 週期</td></tr><tr><td style="text-align:left;">高芯數滲透率</td><td style="text-align:right;">288→6,912 芯↑，ASP 能見度高</td></tr><tr><td style="text-align:left;">菲律賓廠投產</td><td style="text-align:right;">2025/7 完工，產能瓶頸緩解</td></tr><tr><td style="text-align:left;">CPO 驗證</td><td style="text-align:right;">最終驗證階段，2026 年量產</td></tr></tbody></table><p><strong>綜合判斷：</strong> 未來營收能見度由 AI CAPEX 與 CPO 量產時程共同決定。2026 Q1 營收 38.9 億（YoY +34.7%）驗證動能延續，但單一客戶依存仍為最大不確定因子。</p><hr><h2 id="💡-專家評析-200-450-字" tabindex="-1">💡 專家評析（200-450 字） <a class="header-anchor" href="#💡-專家評析-200-450-字" aria-label="Permalink to &quot;💡 專家評析（200-450 字）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><p><strong>無預收款保護（風險 ⚠️）</strong>：839 萬合約負債比對年營收 107 億，形同無客戶預付款緩衝。一旦縮單，營收直接反映。</p></li><li><p><strong>能見度完全繫於單一客戶</strong>：客戶 A 佔比 63%，無合約負債約束，訂單削減時財報無任何預警指標。</p></li><li><p><strong>指標零預測能力</strong>：8 季 CL 維持 6-8M 幾乎無波動，同期營收從 5.28B 跳升至 10.71B，解釋力為零。</p></li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><p><strong>產品剛需無需預付</strong>：PO 模式反映產品為數據中心不可或缺的連接方案。</p></li><li><p><strong>CPO 量產後的轉變</strong>：CPO 模組客製化程度高，可能轉為部分預付模式。</p></li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>光聖合約負債不適用傳統框架，屬行業特性。應追蹤客戶 CAPEX 與 CPO 驗證進度。</p><hr><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>原始數據</strong>：FinMind TaiwanStockBalanceSheet (OtherCurrentLiabilities + 年報附註合約負債)</li><li><strong>年報資料</strong>：6442 2025 Q4 合併財報附註（合約負債明細 $8,391 千元、收入認列政策、重大合約揭露）</li><li><strong>查詢參數</strong>：stock_id=6442, start=2023-01-01, end=2025-12-31</li><li><strong>數據查詢日期</strong>：2026-05-04</li></ul>',31)])])}const p=a(i,[["render",o]]);export{c as __pageData,p as default};
